There is a miscompilation issue report in LoopVectorize: 

Reproducer: https://godbolt.org/z/Y6sYGTfxE
Testcase:
```c
#include <stdint.h>
#include <stdio.h>
#define BS_VEC(type, num) type __attribute__((vector_size(num * sizeof(type))))
uint64_t BS_CHECKSUM;
int16_t count = 6;
int main()
{
    uint16_t BS_VAR_1 = 40854u;
    BS_VEC(uint64_t, 4) BS_VAR_2 = {};
    uint16_t BS_TEMP_595 = count < 5ull ? count : 5ull;
#pragma clang loop interleave_count(2)
    for (uint16_t BS_INC_0 = 0; BS_INC_0 < BS_TEMP_595; BS_INC_0 += 1)
    {
        BS_VAR_2 &= 0;
        BS_VAR_1 ^= BS_INC_0;
        BS_VAR_2 = (BS_VEC(uint64_t, 4)){ 0, BS_INC_0, 0, 0 };
    }
    BS_CHECKSUM = BS_VAR_1;
    printf("BackSmith Checksum = 0x%016llx\n", BS_CHECKSUM);
}
```

`opt-bisect` points to `LoopVectorize`.

The maintainers proposed the following patch to fix the issue:

commit 2b2582cd3b9ef6132a73881ebd10f846ee018dda
Author: Florian Hahn <flo@fhahn.com>
Date:   Thu Feb 12 22:17:49 2026 +0000

    [VPlan] Update isUniformAcrossVFsAndUFs to account for sinking.

    Recipes can be sunk now. In those cases, the sunk recipes are outside
    the loop region, but may not be uniform across VF and UF.

    Update the code to only exit early if the recipe is defined before the
    region. Without DT available, the easiest way to check is just if it is
    in the entry/preheader block.

    Fixes https://github.com/llvm/llvm-project/issues/181002.
    Fixes https://github.com/llvm/llvm-project/issues/180781.

diff --git a/llvm/lib/Transforms/Vectorize/VPlanUtils.cpp b/llvm/lib/Transforms/Vectorize/VPlanUtils.cpp
index 7de505f688e8..f5318bb1c651 100644
--- a/llvm/lib/Transforms/Vectorize/VPlanUtils.cpp
+++ b/llvm/lib/Transforms/Vectorize/VPlanUtils.cpp
@@ -399,18 +399,22 @@ bool vputils::isUniformAcrossVFsAndUFs(VPValue *V) {
     return true;

   VPRecipeBase *R = V->getDefiningRecipe();
-  if (R && V->isDefinedOutsideLoopRegions()) {
+  VPBasicBlock *VPBB = R ? R->getParent() : nullptr;
+  VPlan *Plan = VPBB ? VPBB->getPlan() : nullptr;
+  if (VPBB &&
+      (VPBB == Plan->getVectorPreheader() || VPBB == Plan->getEntry())) {
     if (match(V->getDefiningRecipe(),
               m_VPInstruction<VPInstruction::CanonicalIVIncrementForPart>()))
       return false;
     return all_of(R->operands(), isUniformAcrossVFsAndUFs);
   }

-  auto *CanonicalIV =
-      R->getParent()->getEnclosingLoopRegion()->getCanonicalIV();
-  // Canonical IV chain is uniform.
-  if (V == CanonicalIV || V == CanonicalIV->getBackedgeValue())
-    return true;
+  if (VPRegionBlock *EnclosingRegion = VPBB->getEnclosingLoopRegion()) {
+    auto *CanonicalIV = EnclosingRegion->getCanonicalIV();
+    // Canonical IV chain is uniform.
+    if (V == CanonicalIV || V == CanonicalIV->getBackedgeValue())
+      return true;
+  }

   return TypeSwitch<const VPRecipeBase *, bool>(R)
       .Case([](const VPDerivedIVRecipe *R) { return true; })


